  ('islands-e3452428-moex-00080', 'islands-e3452428', 'islands-e3452428-moex-114-4dccc0e6', 'sub-islands-e3452428-02', NULL, 'single_choice', '行政院會議是由院長擔任主席並固定召開的會議，下列何者不屬於其主要功能？ 跨部會協調  政策合法化  凝聚政府共識  審議決算報告', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "06786d62fb55", "answer_pdf_sha1": "242e83f0aff7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0512", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00081', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政法法源之敘述，下列何者正確？ 兒童權利公約施行法為成文法源 地方自治法規非屬於成文法源，但得作為不成文法源 不成文法源不包括習慣法 法規命令非法律，不屬於成文法源', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00082', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者為對物之一般處分？ 土地現值之公告  小學學區之劃分  路邊停車位之劃定  轄區鄰里之調整', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00083', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政法之一般法律原則，下列敘述何者正確？ 信賴保護原則亦適用於機關內部事務分配之行政規則 誠實信用原則亦適用於人民之行為 明確性原則不適用於行政契約 正當程序原則不適用於事實行為', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00084', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '司法機關得審查行政機關行使裁量權之範圍為： 裁量是否適當    裁量是否逾越法定之範圍 裁量是否符合風土民情  裁量是否符合政府政策之目的', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00085', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於行政機關之私法行為，下列敘述何者錯誤？ 國家為達成給付行政任務，得選擇以公法上行為或私法上行為作為實施之手段 因行政輔助行為所生之爭議，除法律有特別規定外，其訴訟由普通法院管轄 基本權利對於行政機關之私法行為具有拘束力 國家以私法形式達成行政目的之行為，完全排除公法原則之適用', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00086', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者非屬公法性質之法律關係？ 公平交易委員會與私人企業就產品搭售事項成立和解契約 市立動物園販售門票供民眾參觀 公立殯儀館按利用規則向人民收取使用規費 警察機關對違規停放之車輛裁處罰鍰', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00087', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '有關行政法法律關係之發生，下列敘述何者正確？ 單純事實行為，不會產生任何行政法法律關係 由於行政指導本身不具任何法律上強制力，故不會產生任何行政法法律關係 行政契約以私法自治精神為之，故不會產生任何行政法法律關係 民事契約關係中，債權人對債務人請求履行契約，不會產生行政法法律關係 3601', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00088', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '下列何者為行政機關？ 行政院主計總處  經濟部投資審議司  內政部法規委員會  國家表演藝術中心', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL),
  ('islands-e3452428-moex-00089', 'islands-e3452428', 'islands-e3452428-moex-114-d1a761c9', 'sub-islands-e3452428-03', NULL, 'single_choice', '關於自治條例之敘述，下列何者正確？ 基於法律保留原則，地方自治條例不得規範人民的權利與義務 地方自治條例得以命令歇業、吊銷證照為行政罰之種類 直轄市之自治條例定有罰則者，應經行政院核定並發布後始生法定效力 基於自治事項與委辦事項之區別，地方自治團體僅得針對委辦事項自行訂定罰則', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:57+00:00", "source_pdf_sha1": "5eb885d020bc", "answer_pdf_sha1": "842f6c46da6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "601", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "islands", "civil_category": "一般民政"}'::jsonb, NULL)
